+/**
+ * Sanitize hot spot attributes to prevent XSS attacks
+ * Filters out dangerous event handler attributes
+ * @param {Object} attributes - Raw attributes from config
+ * @returns {Object} Sanitized attributes
+ */
+function sanitizeHotSpotAttributes(attributes) {
+    const sanitized = {};
+    const dangerousPatterns = /^(on|data-)/i;
+    
+    for (const attr in attributes) {
+        if (attributes.hasOwnProperty(attr)) {
+            // Block event handler attributes (onclick, onmouseover, etc.)
+            if (/^on/i.test(attr)) {
+                continue;
+            }
+            // Block data attributes that could be used for XSS
+            if (/^data-/i.test(attr)) {
+                continue;
+            }
+            sanitized[attr] = attributes[attr];
+        }
+    }
+    
+    return sanitized;
+}
