+import { parse } from "acorn";
+import { generate } from "escodegen";
+
+/**
+ * Safely evaluates code by parsing and validating AST before execution.
+ * This prevents arbitrary code injection by restricting what can be executed.
+ */
+export function safeEvalInContext(code: string, context: any = {}): any {
+  try {
+    // Parse the code to validate syntax
+    const ast = parse(code, { ecmaVersion: 2020 });
+    
+    // Validate that the AST only contains safe operations
+    // Reject any eval, Function constructor, or require calls
+    const hasUnsafeOps = hasUnsafeOperations(ast);
+    if (hasUnsafeOps) {
+      throw new Error("Unsafe code detected: eval, Function constructor, or require calls are not allowed");
+    }
+    
+    // Create a safe context with only whitelisted properties
+    const safeContext = createSafeContext(context);
+    
+    // Execute in restricted context
+    return new Function("context", "return " + generate(ast))(safeContext);
+  } catch (e) {
+    throw new Error(`Failed to safely evaluate code: ${e.message}`);
+  }
+}
+
+function hasUnsafeOperations(ast: any): boolean {
+  // Check for dangerous patterns in AST
+  const dangerousPatterns = ["eval", "Function", "require"];
+  return dangerousPatterns.some(pattern => 
+    ast.type === "CallExpression" && 
+    ast.callee && 
+    (ast.callee.name === pattern || ast.callee.type === "MemberExpression")
+  );
+}
+
+function createSafeContext(context: any): any {
+  // Create a restricted context with only safe properties
+  const safeContext = {};
+  for (const key in context) {
+    if (typeof context[key] === "function") {
+      // Only allow whitelisted safe functions
+      if (["toString", "length", "name"].includes(key)) {
+        safeContext[key] = context[key];
+      }
+    } else {
+      safeContext[key] = context[key];
+    }
+  }
+  return safeContext;
 }
